const{SlashCommandBuilder:SlashCommandBuilder,EmbedBuilder:EmbedBuilder}=require("discord.js"),fetch=require("node-fetch"),config=require("../config");class CollectionPnlCommand{constructor(){}getCommandData(){return(new SlashCommandBuilder).setName("collectionpnl").setDescription("Compute realized PnL for a wallet in a specific collection").addStringOption((option=>option.setName("wallet").setDescription("Wallet address (0x...)").setRequired(!0))).addStringOption((option=>option.setName("slug").setDescription("Collection slug (e.g. nightglyders)").setRequired(!0))).addStringOption((option=>option.setName("chain").setDescription("Blockchain network").setRequired(!1).addChoices({name:"Ethereum",value:"ethereum"},{name:"ApeChain",value:"ape_chain"},{name:"Base",value:"base"},{name:"Polygon",value:"polygon"},{name:"Arbitrum",value:"arbitrum"},{name:"Optimism",value:"optimism"})))}async execute(interaction){try{const wallet=interaction.options.getString("wallet",!0).toLowerCase(),slug=interaction.options.getString("slug",!0),chain=interaction.options.getString("chain")||"ethereum";console.log(`🔍 /collectionpnl for wallet ${wallet}, slug ${slug} on ${chain}`);const nftTracker=new(require("./nftTracker")),collectionInfo=await nftTracker.getCollectionInfoBySlug(slug,chain),contracts=Array.isArray(collectionInfo?.contracts)?collectionInfo.contracts.filter((c=>(c?.chain||"").toLowerCase()===(chain||"ethereum").toLowerCase())).map((c=>(c.address||"").toLowerCase())).filter(Boolean):[];if(0===contracts.length)return await interaction.reply({content:"❌ No contracts found for this collection on selected chain.",ephemeral:!0}),void await nftTracker.disconnect();const apiKey=config.opensea.apiKey,occurredAfter=Math.floor((Date.now()-31536e6)/1e3),eventsUrl=`https://api.opensea.io/api/v2/events/accounts/${wallet}?event_type=sale&event_type=mint&event_type=bid_accepted&occurred_after=${occurredAfter}&limit=100`,res=await fetch(eventsUrl,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(!res.ok)return await interaction.reply({content:`❌ Failed to fetch account events: ${res.status} ${res.statusText}`,ephemeral:!0}),void await nftTracker.disconnect();const data=await res.json(),events=Array.isArray(data.asset_events)?data.asset_events:[],getContract=evt=>(evt.contract||evt.asset?.asset_contract?.address||evt.nft?.contract||"").toLowerCase(),getTokenId=evt=>(evt.nft?.identifier||evt.asset?.token_id||evt.token_id||"").toString(),getSeller=evt=>(evt.seller?.address||evt.from_account?.address||"").toLowerCase(),saleEvents=events.filter((evt=>{const contractAddr=getContract(evt),seller=getSeller(evt);return contractAddr&&contracts.includes(contractAddr)&&seller===wallet}));let totalPnL=0,totalPnLUSD=0,realizedSales=0,totalBuy=0,totalSell=0;const rows=[];for(const evt of saleEvents)try{let salePrice=0,salePriceUSD=0,decimals=18;evt.payment_token&&(decimals=Number(evt.payment_token.decimals??18)),null!=evt.sale_price?salePrice=Number(evt.sale_price)/Math.pow(10,decimals):evt.payment&&evt.payment.quantity&&(salePrice=Number(evt.payment.quantity)/Math.pow(10,Number(evt.payment.decimals??18))),evt.payment?.usd_amount&&(salePriceUSD=Number(evt.payment.usd_amount));const contractAddress=getContract(evt),tokenId=getTokenId(evt),purchase=await nftTracker.recoverPurchaseData(contractAddress,tokenId,wallet,chain);if(!purchase||!Number.isFinite(purchase.price))continue;const pnl=salePrice-purchase.price,pnlUSD=(salePriceUSD||0)-(purchase.priceUSD||0);totalPnL+=pnl,totalPnLUSD+=pnlUSD,realizedSales+=1,totalBuy+=purchase.price,totalSell+=salePrice,rows.push({tokenId:tokenId,buy:purchase.price,sell:salePrice,pnl:pnl})}catch(e){continue}const nativeSymbol=nftTracker.getNativeTokenSymbol(chain),embed=(new EmbedBuilder).setTitle(`📈 PnL for ${slug}`).setColor(49151).addFields({name:"👛 Wallet",value:wallet,inline:!1},{name:"🔷 Chain",value:chain.toUpperCase(),inline:!0},{name:"🧾 Sales Count",value:String(realizedSales),inline:!0},{name:"💰 Total Buy",value:`${totalBuy.toFixed(4)} ${nativeSymbol}`,inline:!0},{name:"💵 Total Sell",value:`${totalSell.toFixed(4)} ${nativeSymbol}`,inline:!0},{name:"📊 Realized PnL",value:`${totalPnL>=0?"+":""}${totalPnL.toFixed(4)} ${nativeSymbol}`,inline:!0}).setFooter({text:"⚡ Powered by STPNGPT • /collectionpnl"}).setTimestamp();if(rows.length>0){rows.sort(((a,b)=>b.pnl-a.pnl));const top=rows.slice(0,5).map((r=>`#${r.tokenId}: ${r.pnl>=0?"+":""}${r.pnl.toFixed(4)} ${nativeSymbol}`)).join("\n"),bottom=rows.slice(-5).map((r=>`#${r.tokenId}: ${r.pnl>=0?"+":""}${r.pnl.toFixed(4)} ${nativeSymbol}`)).join("\n");embed.addFields({name:"🏆 Top PnL",value:top||"—",inline:!1},{name:"⚠️ Worst PnL",value:bottom||"—",inline:!1})}await interaction.reply({embeds:[embed]}),await nftTracker.disconnect()}catch(error){console.error("❌ Error in collectionpnl command:",error);const errorMessage="❌ An error occurred while calculating PnL.";try{await interaction.reply({content:errorMessage,ephemeral:!0})}catch(_){}}}}module.exports=CollectionPnlCommand;